import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import datasets, transforms, models
import requests
from io import BytesIO

def download_model(url):
    response = requests.get(url)
    response.raise_for_status()
    return torch.load(BytesIO(response.content))

def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.SGD(model.parameters(), lr=learning_rate, momentum=0.9)

    for epoch in range(num_epochs):
        running_loss = 0.0
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {running_loss/len(train_loader)}')

def main():
    url = 'https://example.com/model.pth'  # Replace with the actual URL
    model = download_model(url)
    
    # Assume model is a torchvision model; adjust as necessary
    model.fc = nn.Linear(model.fc.in_features, 10)  # Modify output layer for your dataset

    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor()
    ])

    train_dataset = datasets.ImageFolder(root='path/to/train/dataset', transform=transform)
    train_loader = torch.utils.data.DataLoader(train_dataset, batch_size=32, shuffle=True)

    fine_tune_model(model, train_loader)

if __name__ == '__main__':
    main()